    18→import TimeSpanSelector, {
    19→  DisplayTimeSpan,
    20→  getDisplayTimeSpanByLabel,
    21→  type TimeSpan,
    22→} from "./timespan-selector";
    23→
    24→export interface SelectedFilter {
    25→  expr: string;
    26→  values: Map<string, QueryPattern>;
    27→}
    28→
    29→interface FilterProps {
    30→  className?: string;
    31→  filterSpecs: FilterSpec[];
    32→  defaultTimeSpan?: string;
    33→  showTimeSpanSelector?: boolean;
    34→  showRefresh?: boolean;
    35→  showAutoRefresh?: boolean;
    36→  onFilterChange?: (filter: SelectedFilter) => void;
    37→  onTimeSpanChange?: (range: TimeSpan) => void;
    38→  timezone?: string;
    39→
    40→  // Callback to load items for a filter selector
    41→  onLoadSourceData?: (query: SQLQuery) => Promise<string[]>;
    42→
    43→  // Callback to reset dashboard layout to default
    44→  onResetLayout?: () => void;
    45→
    46→  children?: React.ReactNode;
    47→}
    48→
    49→type FilterState = Record<string, never>;
    50→
    51→class DashboardFilterComponent extends Component<FilterProps, FilterState> {
    52→  //
    53→  // These variables are NOT UI state, we don't define them in the react.state which would cause re-rendering when updating these states
    54→  //
    55→  // Track the selected filter and its values
    56→  private selectedFilters: Map<string, QueryPattern>;
    57→
    58→  // Track if one selector needs to re-load items
    59→  private reloadingRequiredState: Map<number, boolean>;
    60→
    61→  // Track the selected time span
    62→  private defaultTimeSpan: DisplayTimeSpan;
    63→  private timeSpanSelectorRef = React.createRef<TimeSpanSelector>();
    64→
    65→  private selectorContainerRef = React.createRef<HTMLDivElement>();
    66→  private scrollLeftButtonRef = React.createRef<HTMLButtonElement>();
    67→  private scrollRightButtonRef = React.createRef<HTMLButtonElement>();
    68→
    69→  // Store refs to Selector components by filter name
    70→  private selectorRefs = new Map<string, React.RefObject<SelectorRef | null>>();
    71→
    72→  private nameConverts: Map<string, (name: string) => string>;
    73→  private timeFilterSpec: DateTimeFilterSpec | undefined;
    74→  private filterSpecByName: Map<string, SelectorFilterSpec>;
    75→
    76→  constructor(props: FilterProps) {
    77→    super(props);
    78→
    79→    this.timeFilterSpec = props.filterSpecs.find(
    80→      (f): f is DateTimeFilterSpec => f.filterType === "date_time"
    81→    );
    82→    const defaultTimeSpanLabel =
    83→      this.timeFilterSpec?.defaultTimeSpan || props.defaultTimeSpan || "Last 15 Mins";
    84→    this.defaultTimeSpan = getDisplayTimeSpanByLabel(defaultTimeSpanLabel);
    85→
    86→    this.reloadingRequiredState = new Map();
    87→
    88→    this.selectedFilters = new Map<string, QueryPattern>();
    89→
    90→    this.nameConverts = new Map();
    91→    this.filterSpecByName = new Map();
    92→    props.filterSpecs.forEach((filter) => {
    93→      if (filter.filterType !== "select") {
    94→        return;
    95→      }
    96→      this.filterSpecByName.set(filter.name, filter);
    97→      if (filter.nameConverter) {
    98→        this.nameConverts.set(filter.name, filter.nameConverter);
    99→      } else {
   100→        this.nameConverts.set(filter.name, (name) => name);
   101→      }
   102→
   103→      // Initialize defaultPattern if provided
   104→      if (filter.defaultPattern) {
   105→        const comparator = ComparatorManager.parseComparator(filter.defaultPattern.comparator);
   106→        const isMultiValue = comparator.allowMultiValue ?? false;
   107→        const pattern = new QueryPattern(
   108→          isMultiValue,
   109→          filter.defaultPattern.comparator,
   110→          filter.defaultPattern.values
   111→        );
   112→        this.selectedFilters.set(filter.name, pattern);
   113→      }
   114→    });
   115→
   116→    this.onTimeSpanChangeCallback = this.onTimeSpanChangeCallback.bind(this);
   117→    this.onItemSelectedCallback = this.onItemSelectedCallback.bind(this);
   118→    this.beforeLoadItemCallback = this.beforeLoadItemCallback.bind(this);
   119→    this.afterLoadItemCallback = this.afterLoadItemCallback.bind(this);
   120→    this.onLoadItemCallback = this.onLoadItemCallback.bind(this);
   121→  }
   122→
   123→  componentDidMount(): void {
   124→    // Init the scroll button visibility
   125→    this.handleSelectorContainerScroll();
   126→
   127→    // const initialTimeSpan = this.getSelectedTimeSpan();
   128→    // if (this.props.onTimeSpanChange && initialTimeSpan) {
   129→    //   this.props.onTimeSpanChange(initialTimeSpan);
   130→    // }
   131→  }
   132→
   133→  componentDidUpdate(prevProps: FilterProps): void {
   134→    // Emit filter changes when filterSpecs change and defaultPatterns are initialized
   135→    if (this.props.filterSpecs !== prevProps.filterSpecs && this.props.onFilterChange) {
   136→      this.props.onFilterChange(this.getSelectedFilter());
   137→    }
   138→  }
   139→
   140→  shouldComponentUpdate(nextProps: FilterProps): boolean {
   141→    // Update the selected variables before rendering
   142→    if (this.props.filterSpecs !== nextProps.filterSpecs) {
   143→      this.selectedFilters = new Map<string, QueryPattern>();
   144→
   145→      this.timeFilterSpec = nextProps.filterSpecs.find(
   146→        (f): f is DateTimeFilterSpec => f.filterType === "date_time"
   147→      );
   148→      this.nameConverts = new Map();
   149→      this.filterSpecByName = new Map();
   150→      nextProps.filterSpecs.forEach((filter) => {
   151→        if (filter.filterType !== "select") {
   152→          return;
   153→        }
   154→        this.filterSpecByName.set(filter.name, filter);
   155→        if (filter.nameConverter) {
   156→          this.nameConverts.set(filter.name, filter.nameConverter);
   157→        } else {
   158→          this.nameConverts.set(filter.name, (name) => name);
   159→        }
   160→
   161→        // Initialize defaultPattern if provided
   162→        if (filter.defaultPattern) {
   163→          const comparator = ComparatorManager.parseComparator(filter.defaultPattern.comparator);
   164→          const isMultiValue = comparator.allowMultiValue ?? false;
   165→          const pattern = new QueryPattern(
   166→            isMultiValue,
   167→            filter.defaultPattern.comparator,
   168→            filter.defaultPattern.values
   169→          );
   170→          this.selectedFilters.set(filter.name, pattern);
   171→        }
   172→      });
   173→    }
   174→
   175→    // The default implementation
   176→    return true;
   177→  }
   178→
   179→  onTimeSpanChangeCallback(newSelected: DisplayTimeSpan) {
   180→    // Reset all selectors to allow re-loading
   181→    this.reloadingRequiredState.clear();
   182→
   183→    // Broadcast the change to the parent component
   184→    if (this.props.onTimeSpanChange) {
   185→      this.props.onTimeSpanChange(newSelected.getTimeSpan());
   186→    }
   187→  }
   188→
   189→  onItemSelectedCallback = (
   190→    index: number,
   191→    filterSpec: SelectorFilterSpec,
   192→    pattern: QueryPattern
   193→  ) => {
   194→    const { filterSpecs, onFilterChange } = this.props;
   195→
   196→    // Treat null or patterns with empty values as clearing the filter
   197→    if (pattern === null || pattern.values.length === 0) {
   198→      this.selectedFilters.delete(filterSpec.name);
   199→    } else {
   200→      this.selectedFilters.set(filterSpec.name, pattern);
   201→    }
   202→
   203→    // Clear other filter states so that they will be reloaded
   204→    for (let i = index + 1; i < filterSpecs.length; i++) {
   205→      this.reloadingRequiredState.set(i, true);
   206→    }
   207→
   208→    // Notification
   209→    if (onFilterChange) {
   210→      let queryExpression = "";
   211→      this.selectedFilters.forEach((pattern, alias) => {
   212→        if (queryExpression.length > 0) {
   213→          queryExpression += " AND ";
   214→        }
   215→        queryExpression += this.toFilterExpression(alias, pattern);
   216→      });
   217→
   218→      onFilterChange({ expr: queryExpression, values: this.selectedFilters });
   219→    }
   220→  };
   221→
   222→  beforeLoadItemCallback(index: number): boolean {
   223→    const isReloadingRequired = this.reloadingRequiredState.get(index);
   224→    return isReloadingRequired === undefined ? true : isReloadingRequired;
   225→  }
   226→
   227→  afterLoadItemCallback(index: number) {
   228→    this.reloadingRequiredState.set(index, false);
   229→  }
   230→
   231→  async onLoadItemCallback(filterIndex: number) {
   232→    const { filterSpecs, onLoadSourceData } = this.props;
   233→    const thisFilterSpec = filterSpecs[filterIndex];
   234→    if (thisFilterSpec.filterType !== "select") {
   235→      return [];
   236→    }
   237→
   238→    // Handle inline data source
   239→    if (thisFilterSpec.datasource.type === "inline") {
   240→      return thisFilterSpec.datasource.values;
   241→    }
   242→
   243→    // Handle SQL data source
   244→    const filterExpressionList = [];
   245→
   246→    // Apply other selectors' values as filter
   247→    if (thisFilterSpec.onPreviousFilters === undefined || thisFilterSpec.onPreviousFilters) {
   248→      for (let p = 0; p < filterIndex; p++) {
   249→        const otherFilterSpec = filterSpecs[p];
   250→        if (otherFilterSpec.filterType !== "select") {
   251→          continue;
   252→        }
   253→        const pattern = this.selectedFilters.get(otherFilterSpec.name);
   254→        if (pattern !== undefined && pattern !== null && pattern.values.length > 0) {
   255→          filterExpressionList.push(this.toFilterExpression(otherFilterSpec.name, pattern));
   256→        }
   257→      }
   258→    }
   259→
   260→    if (!onLoadSourceData) {
   261→      return [];
   262→    }
   263→
   264→    // Use SQLQueryBuilder for clean SQL transformation
   265→    const sql = new SQLQueryBuilder(thisFilterSpec.datasource.sql)
   266→      .timeSpan(this.getSelectedTimeSpan(), this.props.timezone ?? "UTC")
   267→      .filterExpression(filterExpressionList.join(" AND "))
   268→      .build();
   269→
   270→    const dimensions = await onLoadSourceData({
   271→      sql,
   272→    });
   273→
   274→    return dimensions.map((dim) => ({
   275→      value: dim,
   276→      label: dim,
   277→    }));
   278→  }
   279→
   280→  public getSelectedFilter(): SelectedFilter {
   281→    let expr = "";
   282→    this.selectedFilters.forEach((pattern, alias) => {
   283→      if (expr.length > 0) {
   284→        expr += " AND ";
   285→      }
   286→      expr += this.toFilterExpression(alias, pattern);
   287→    });
   288→    return { expr: expr, values: this.selectedFilters };
   289→  }
   290→
   291→  private asSqlString(value: string): string {
   292→    return `'${SqlUtils.escapeSqlString(value)}'`;
   293→  }
   294→
   295→  private replaceAllLiteral(input: string, token: string, value: string): string {
   296→    // Avoid regex replacement; tokens are literals like "{value}".
   297→    return input.split(token).join(value);
   298→  }
   299→
   300→  private buildExpressionFromTemplate(
   301→    template: string,
   302→    name: string,
   303→    pattern: QueryPattern
   304→  ): string {
   305→    const values = pattern.values ?? [];
   306→    const value = this.asSqlString(values[0] ?? "");
   307→    const valuesList = values.map((v) => this.asSqlString(v)).join(",");
   308→    const valuesArray = `[${valuesList}]`;
   309→
   310→    let result = template;
   311→    result = this.replaceAllLiteral(result, "{name}", name);
   312→    result = this.replaceAllLiteral(result, "{value}", value);
   313→    result = this.replaceAllLiteral(result, "{values}", valuesList);
   314→    result = this.replaceAllLiteral(result, "{valuesArray}", valuesArray);
   315→    return result;
   316→  }
   317→
   318→  private toFilterExpression(alias: string, pattern: QueryPattern): string {
   319→    const converter = this.nameConverts.get(alias) ?? ((name: string) => name);
   320→    const name = converter(alias);
   321→
   322→    const spec = this.filterSpecByName.get(alias);
   323→    const template = spec?.expressionTemplate?.[pattern.comparator];
   324→    if (template && template.length > 0) {
   325→      return this.buildExpressionFromTemplate(template, name, pattern);
   326→    }
   327→
   328→    return pattern.toQueryString(name);
   329→  }
   330→
   331→  public getSelectedTimeSpan(): TimeSpan {
   332→    // If all time span components are disabled, return a default time span
   333→    if (
   334→      this.props.showTimeSpanSelector === false &&
   335→      this.props.showRefresh === false &&
   336→      this.props.showAutoRefresh === false
   337→    ) {
   338→      // Return a default 1 hour timespan from now
   339→      const now = new Date();
   340→      const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
   341→      return {
   342→        startISO8601: oneHourAgo.toISOString(),
   343→        endISO8601: now.toISOString(),
   344→      };
   345→    }
   346→
   347→    // If time span selector specifically is disabled but others are enabled, still return default
   348→    if (this.props.showTimeSpanSelector === false || !this.timeSpanSelectorRef.current) {
   349→      const now = new Date();
   350→      const oneHourAgo = new Date(now.getTime() - 60 * 60 * 1000);
   351→      return {
   352→        startISO8601: oneHourAgo.toISOString(),
   353→        endISO8601: now.toISOString(),
   354→      };
   355→    }
   356→
   357→    return this.timeSpanSelectorRef.current?.getSelectedTimeSpan().getTimeSpan();
   358→  }
   359→
   360→  public setSelectedTimeSpan(timeSpan: TimeSpan) {
   361→    if (this.props.showTimeSpanSelector === false || !this.timeSpanSelectorRef.current) {
   362→      return; // Do nothing if time span selector is disabled
   363→    }
   364→    const label = `${timeSpan.startISO8601} - ${timeSpan.endISO8601}`;
   365→
   366→    this.timeSpanSelectorRef.current?.setSelectedTimeSpan(getDisplayTimeSpanByLabel(label));
   367→  }
   368→
   369→  public setFilter(filterName: string, value: string) {
   370→    const filterSpec = this.filterSpecByName.get(filterName);
   371→    if (!filterSpec) {
   372→      return; // Filter not found
   373→    }
   374→
   375→    // Create a QueryPattern with the value
   376→    const comparator = ComparatorManager.parseComparator("=");
   377→    const pattern = new QueryPattern(false, comparator.name, [value]);
   378→
   379→    // Update UI state directly via ref
   380→    const selectorRef = this.selectorRefs.get(filterName);
   381→    if (selectorRef?.current) {
   382→      selectorRef.current.setPattern(pattern);
   383→    }
   384→
   385→    // Find the index of this filter in the filterSpecs array
   386→    const filterIndex = this.props.filterSpecs.findIndex((f) => f === filterSpec);
   387→    if (filterIndex !== -1) {
   388→      // Trigger the callback to notify parent component
   389→      this.onItemSelectedCallback(filterIndex, filterSpec, pattern);
   390→    }
   391→  }
   392→
   393→  private handleSelectorContainerScroll = () => {
   394→    if (this.selectorContainerRef.current) {
   395→      const { scrollLeft, scrollWidth, clientWidth } = this.selectorContainerRef.current;
   396→
   397→      // Show left button if scrolled
   398→      // Directly control the DOM to avoid re-rendering
   399→      this.scrollLeftButtonRef.current?.classList.toggle("hidden", scrollLeft <= 0);
   400→
   401→      // Show right button if not fully scrolled to the right
   402→      // Directly control the DOM to avoid re-rendering
   403→      this.scrollRightButtonRef.current?.classList.toggle(
   404→        "hidden",
   405→        scrollLeft + clientWidth >= scrollWidth
   406→      );
   407→    }
   408→  };
   409→
   410→  private scrollLeft = () => {
   411→    if (this.selectorContainerRef.current) {
   412→      this.selectorContainerRef.current.scrollBy({ left: -200, behavior: "smooth" });
   413→    }
   414→  };
   415→
   416→  private scrollRight = () => {
   417→    if (this.selectorContainerRef.current) {
   418→      this.selectorContainerRef.current.scrollBy({ left: 200, behavior: "smooth" });
   419→    }
   420→  };
   421→
   422→  private handleRefreshTimeSpan = () => {
   423→    const selected = this.timeSpanSelectorRef.current?.getSelectedTimeSpan();
   424→    if (!selected) {
   425→      return;
   426→    }
   427→    // Recalculate "last N mins/hours" spans and emit to parent.
   428→    selected.reCalculateTimeSpan();
   429→    this.onTimeSpanChangeCallback(selected);
   430→  };
   431→
   432→  render() {
   433→    // Logger.trace("Rendering DashboardFilterComponent");
   434→
   435→    const { className, filterSpecs } = this.props;
   436→    const hasTimeFilterSpec = filterSpecs.some((f) => f.filterType === "date_time");
   437→
   438→    return (
   439→      <div className={cn("flex items-center justify-between gap-2", className)}>
   440→        <div
   441→          ref={this.selectorContainerRef}
   442→          onScroll={this.handleSelectorContainerScroll}
   443→          className="relative flex items-center overflow-x-auto whitespace-nowrap flex-1"
   444→        >
   445→          {filterSpecs.map((filter, index) => {
   446→            if (filter.filterType === "date_time") {
   447→              const timeFilterInputId = `time-filter-${filter.alias}`;
   448→              return (
   449→                <div key={filter.alias} className="shrink-0">
   450→                  <div className="relative">
   451→                    <FloatingLabel
   452→                      htmlFor={timeFilterInputId}
   453→                      className="pointer-events-none bg-transparent dark:bg-transparent"
   454→                    >
   455→                      {filter.timeColumn}
   456→                    </FloatingLabel>
   457→                    <TimeSpanSelector
   458→                      ref={this.timeSpanSelectorRef}
   459→                      defaultTimeSpan={this.defaultTimeSpan}
   460→                      showTimeSpanSelector={true}
   461→                      showRefresh={false}
   462→                      showAutoRefresh={false}
   463→                      size="sm"
   464→                      buttonClassName="h-8 rounded-r-none"
   465→                      onSelectedSpanChanged={this.onTimeSpanChangeCallback}
   466→                    />
   467→                  </div>
   468→                </div>
   469→              );
   470→            }
   471→
   472→            // Get or create ref for this selector
   473→            if (!this.selectorRefs.has(filter.name)) {
   474→              this.selectorRefs.set(filter.name, React.createRef<SelectorRef>());
   475→            }
   476→            const selectorRef = this.selectorRefs.get(filter.name)!;
   477→
   478→            return (
   479→              <Selector
   480→                ref={selectorRef}
   481→                className={cn("h-8", {
   482→                  "rounded-l": index === 0,
   483→                  "rounded-r": index === filterSpecs.length - 1,
   484→                  "rounded-l rounded-r": index === 0 && index === filterSpecs.length - 1,
   485→                })}
   486→                placeholder={filter.displayText ? filter.displayText : filter.name}
   487→                key={filter.name}
   488→                defaultItems={[]}
   489→                defaultPattern={this.selectedFilters.get(filter.name)}
   490→                supportedComparators={filter.supportedComparators}
   491→                beforeLoadItem={() => this.beforeLoadItemCallback(index)}
   492→                onLoadItem={() => this.onLoadItemCallback(index)}
   493→                afterLoadItem={() => this.afterLoadItemCallback(index)}
   494→                onItemSelected={(pattern) => this.onItemSelectedCallback(index, filter, pattern)}
   495→              />
   496→            );
   497→          })}
   498→        </div>
   499→
   500→        <div className="flex items-center gap-1 right-0">
   501→          {this.props.children}
   502→
   503→          {this.props.onResetLayout && (
   504→            <Button
   505→              type="button"
   506→              variant="outline"
   507→              className="h-8 px-2 text-xs"
   508→              aria-label="Reset Layout"
   509→              title="Reset panel layout to default"
   510→              onClick={this.props.onResetLayout}
   511→            >
   512→              Reset Layout
   513→            </Button>
   514→          )}
   515→
   516→          {hasTimeFilterSpec && (
   517→            <Button
   518→              type="button"
   519→              variant="outline"
   520→              className="h-8 w-8 p-0"
   521→              aria-label="Refresh"
   522→              title="Refresh"
   523→              onClick={this.handleRefreshTimeSpan}
   524→            >
   525→              <RefreshCcw className="h-4 w-4" />
   526→            </Button>
   527→          )}
   528→
   529→          {!hasTimeFilterSpec &&
   530→            (this.props.showTimeSpanSelector !== false ||
   531→              this.props.showRefresh !== false ||
   532→              this.props.showAutoRefresh !== false) && (
   533→              <TimeSpanSelector
   534→                ref={this.timeSpanSelectorRef}
   535→                defaultTimeSpan={this.defaultTimeSpan}
   536→                size="sm"
   537→                showTimeSpanSelector={this.props.showTimeSpanSelector}
   538→                showRefresh={this.props.showRefresh}
   539→                showAutoRefresh={this.props.showAutoRefresh}
   540→                onSelectedSpanChanged={this.onTimeSpanChangeCallback}
   541→              />
   542→            )}
   543→        </div>
   544→      </div>
   545→    );
   546→  }
   547→}
   548→
   549→export default DashboardFilterComponent;
