   199→        filter: {
   200→          ...config.filter,
   201→          selectors: [
   202→            {
   203→              type: "filter",
   204→              name: "filters",
   205→              fields: updatedSpecs,
   206→            },
   207→          ],
   208→        },
   209→      });
   210→      setEditingFilter(null);
   211→      setEditingFilterIndex(-1);
   212→    },
   213→    [config, editingFilterIndex, saveConfig]
   214→  );
   215→
   216→  // Delete filter
   217→  const handleDeleteFilter = useCallback(
   218→    (index: number) => {
   219→      if (!config) return;
   220→      const updatedSpecs = config.filterSpecs.filter((_, i) => i !== index);
   221→      saveConfig({
   222→        ...config,
   223→        filterSpecs: updatedSpecs,
   224→        filter: {
   225→          ...config.filter,
   226→          selectors: updatedSpecs.length
   227→            ? [
   228→                {
   229→                  type: "filter",
   230→                  name: "filters",
   231→                  fields: updatedSpecs,
   232→                },
   233→              ]
   234→            : undefined,
   235→        },
   236→      });
   237→    },
   238→    [config, saveConfig]
   239→  );
   240→
   241→  // Add section
   242→  const handleAddSection = useCallback(() => {
   243→    if (!config) return;
   244→    const trimmed = newSectionName.trim();
   245→    if (!trimmed) return;
   246→
   247→    const newSection: DashboardGroup = {
   248→      title: trimmed,
   249→      charts: [],
   250→      collapsed: false,
   251→    };
   252→
   253→    saveConfig({
   254→      ...config,
   255→      panels: [...config.panels, newSection],
   256→    });
   257→    setNewSectionName("");
   258→    setShowSectionDialog(false);
   259→  }, [config, newSectionName, saveConfig]);
   260→
   261→  // Rename section
   262→  const handleSectionRename = useCallback(
   263→    (sectionIndex: number, newTitle: string) => {
   264→      if (!config) return;
   265→
   266→      // Find the section by counting groups
   267→      let groupCount = 0;
   268→      const updatedPanels = config.panels.map((item) => {
   269→        if ("charts" in item && Array.isArray((item as DashboardGroup).charts)) {
   270→          if (groupCount === sectionIndex) {
   271→            groupCount++;
   272→            return { ...item, title: newTitle } as DashboardGroup;
   273→          }
   274→          groupCount++;
   275→        }
   276→        return item;
   277→      });
   278→
   279→      saveConfig({ ...config, panels: updatedPanels });
   280→    },
   281→    [config, saveConfig]
   282→  );
   283→
   284→  // Delete section
   285→  const handleSectionDelete = useCallback(
   286→    (sectionIndex: number) => {
   287→      if (!config) return;
   288→
   289→      // Find and remove the section, moving its panels to ungrouped
   290→      let groupCount = 0;
   291→      const updatedPanels: (PanelDescriptor | DashboardGroup)[] = [];
   292→
   293→      for (const item of config.panels) {
   294→        if ("charts" in item && Array.isArray((item as DashboardGroup).charts)) {
   295→          if (groupCount === sectionIndex) {
   296→            // Move panels from deleted section to ungrouped (add to end)
   297→            updatedPanels.push(...(item as DashboardGroup).charts);
   298→          } else {
   299→            updatedPanels.push(item);
   300→          }
   301→          groupCount++;
   302→        } else {
   303→          updatedPanels.push(item);
   304→        }
   305→      }
   306→
   307→      saveConfig({ ...config, panels: updatedPanels });
   308→    },
   309→    [config, saveConfig]
   310→  );
   311→
   312→  // Update section collapse state
   313→  const handleSectionCollapseChange = useCallback(
   314→    (sectionIndex: number, collapsed: boolean) => {
   315→      if (!config) return;
   316→
   317→      // Find the section by counting groups and update its collapsed state
   318→      let groupCount = 0;
   319→      const updatedPanels = config.panels.map((item) => {
   320→        if ("charts" in item && Array.isArray((item as DashboardGroup).charts)) {
   321→          if (groupCount === sectionIndex) {
   322→            groupCount++;
   323→            return { ...item, collapsed } as DashboardGroup;
   324→          }
   325→          groupCount++;
   326→        }
   327→        return item;
   328→      });
   329→
   330→      saveConfig({ ...config, panels: updatedPanels });
   331→    },
   332→    [config, saveConfig]
   333→  );
   334→
   335→  // Build Dashboard model for rendering
   336→  const dashboard = useMemo(() => {
   337→    if (!config) return null;
   338→    return CustomDashboardStorage.toDashboard(config);
   339→  }, [config, dashboardKey]);
   340→
   341→  const allPanels = useMemo(
   342→    () => (config ? flattenPanels(config.panels) : []),
   343→    [config]
   344→  );
   345→
   346→  // Context value for per-widget edit/delete actions
   347→  const panelActions = useMemo<CustomDashboardPanelActions>(
   348→    () => ({
   349→      onEditPanel: handleEditPanel,
   350→      onDeletePanel: handleDeletePanel,
   351→      getPanelIndex: (descriptor) => {
   352→        return allPanels.findIndex((p) => p === descriptor);
   353→      },
   354→    }),
   355→    [handleEditPanel, handleDeletePanel, allPanels]
   356→  );
   357→
   358→  if (!config || !dashboard) {
   359→    return (
   360→      <div className="flex items-center justify-center h-full text-muted-foreground">
   361→        Loading dashboard...
   362→      </div>
   363→    );
   364→  }
   365→
   366→  const hasPanels = allPanels.length > 0;
   367→
   368→  return (
   369→    <div className="flex flex-col h-full w-full overflow-hidden">
   370→      {/* Toolbar */}
   371→      <div className="flex items-center gap-2 px-3 py-2 border-b bg-background shrink-0">
   372→        {/* Dashboard name */}
   373→        {isEditing ? (
   374→          <div className="flex items-center gap-1">
   375→            <Input
   376→              value={editingName}
   377→              onChange={(e) => setEditingName(e.target.value)}
   378→              className="h-7 w-48 text-sm"
   379→              autoFocus
   380→              onKeyDown={(e) => {
   381→                if (e.key === "Enter") handleSaveName();
   382→                if (e.key === "Escape") {
   383→                  setEditingName(config.name);
   384→                  setIsEditing(false);
   385→                }
   386→              }}
   387→            />
   388→            <Button variant="ghost" size="icon" className="h-7 w-7" onClick={handleSaveName}>
   389→              <Check className="h-3.5 w-3.5" />
   390→            </Button>
   391→            <Button
   392→              variant="ghost"
   393→              size="icon"
   394→              className="h-7 w-7"
   395→              onClick={() => {
   396→                setEditingName(config.name);
   397→                setIsEditing(false);
   398→              }}
   399→            >
   400→              <X className="h-3.5 w-3.5" />
   401→            </Button>
   402→          </div>
   403→        ) : (
   404→          <button
   405→            className="flex items-center gap-1.5 text-sm font-medium hover:bg-muted/50 px-2 py-1 rounded transition-colors"
   406→            onClick={() => setIsEditing(true)}
   407→          >
   408→            {config.name}
   409→            <Pencil className="h-3 w-3 text-muted-foreground" />
   410→          </button>
   411→        )}
   412→
   413→        <div className="flex-1" />
   414→
   415→        {/* Add filter */}
   416→        <Button
   417→          variant="outline"
   418→          size="sm"
   419→          className="h-7 text-xs gap-1"
   420→          onClick={() => {
   421→            setEditingFilter(null);
   422→            setEditingFilterIndex(-1);
   423→            setShowFilterDialog(true);
   424→          }}
   425→        >
   426→          <Filter className="h-3.5 w-3.5" />
   427→          Add Filter
   428→        </Button>
   429→
   430→        {/* Add section */}
   431→        <Button
   432→          variant="outline"
   433→          size="sm"
   434→          className="h-7 text-xs gap-1"
   435→          onClick={() => {
   436→            setNewSectionName("");
   437→            setShowSectionDialog(true);
   438→          }}
   439→        >
   440→          <FolderPlus className="h-3.5 w-3.5" />
   441→          Add Section
   442→        </Button>
   443→
   444→        {/* Add panel */}
   445→        <Button
   446→          variant="outline"
   447→          size="sm"
   448→          className="h-7 text-xs gap-1"
   449→          onClick={() => {
   450→            setEditingPanel(null);
   451→            setEditingPanelIndex(-1);
   452→            setShowPanelDialog(true);
   453→          }}
   454→        >
   455→          <Plus className="h-3.5 w-3.5" />
   456→          Add Panel
   457→        </Button>
   458→      </div>
   459→
   460→      {/* Filter chips bar (when filters exist) */}
   461→      {config.filterSpecs.length > 0 && (
   462→        <div className="flex items-center gap-1.5 px-3 py-1.5 border-b bg-muted/30 shrink-0 flex-wrap">
   463→          <span className="text-xs text-muted-foreground mr-1">Filters:</span>
   464→          {config.filterSpecs.map((spec, index) => (
   465→            <div
   466→              key={index}
   467→              className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-background border text-xs"
   468→            >
   469→              <span>{spec.displayText}</span>
   470→              <button
   471→                className="hover:text-foreground text-muted-foreground"
   472→                onClick={() => {
   473→                  setEditingFilter(spec);
   474→                  setEditingFilterIndex(index);
   475→                  setShowFilterDialog(true);
   476→                }}
   477→              >
   478→                <Edit2 className="h-3 w-3" />
   479→              </button>
   480→              <button
   481→                className="hover:text-destructive text-muted-foreground"
   482→                onClick={() => handleDeleteFilter(index)}
   483→              >
   484→                <X className="h-3 w-3" />
   485→              </button>
   486→            </div>
   487→          ))}
   488→        </div>
   489→      )}
   490→
   491→      {/* Dashboard content */}
   492→      <div className="flex-1 min-h-0 overflow-hidden">
   493→        <CustomDashboardContext.Provider value={panelActions}>
   494→          {hasPanels ? (
   495→            <DashboardPage
   496→              dashboardId={`custom-dashboard-${dashboardKey}`}
   497→              key={dashboardKey}
   498→              panels={dashboard}
   499→              filterSpecs={config.filterSpecs}
   500→              showTimeSpanSelector={config.filter.showTimeSpanSelector}
   501→              showRefresh={config.filter.showRefresh}
   502→              showSectionEditControls
   503→              onSectionRename={handleSectionRename}
   504→              onSectionDelete={handleSectionDelete}
   505→              onSectionCollapseChange={handleSectionCollapseChange}
   506→              headerActions={
   507→                <PanelEditOverlay
   508→                  panels={allPanels}
   509→                  onEditPanel={handleEditPanel}
   510→                  onDeletePanel={handleDeletePanel}
   511→                />
   512→              }
   513→            />
   514→          ) : (
   515→            <EmptyDashboardState
   516→              onAddPanel={() => {
   517→                setEditingPanel(null);
   518→                setEditingPanelIndex(-1);
   519→                setShowPanelDialog(true);
   520→              }}
   521→            />
   522→          )}
   523→        </CustomDashboardContext.Provider>
   524→      </div>
   525→
   526→      {/* Dialogs */}
   527→      <PanelConfigDialog
   528→        open={showPanelDialog}
   529→        onOpenChange={setShowPanelDialog}
   530→        onSave={handleAddPanel}
   531→        editingPanel={editingPanel}
   532→      />
   533→
   534→      <DashboardFilterConfigDialog
   535→        open={showFilterDialog}
   536→        onOpenChange={setShowFilterDialog}
   537→        onAdd={handleAddFilter}
   538→        editingFilter={editingFilter}
   539→        onUpdate={handleUpdateFilter}
   540→      />
   541→
   542→      {/* Add Section Dialog */}
   543→      <Dialog open={showSectionDialog} onOpenChange={setShowSectionDialog}>
   544→        <DialogContent className="sm:max-w-md">
   545→          <DialogHeader>
   546→            <DialogTitle>Add Section</DialogTitle>
   547→          </DialogHeader>
   548→          <div className="py-4">
   549→            <Input
   550→              placeholder="Section name"
   551→              value={newSectionName}
   552→              onChange={(e) => setNewSectionName(e.target.value)}
   553→              onKeyDown={(e) => {
   554→                if (e.key === "Enter") handleAddSection();
   555→                if (e.key === "Escape") setShowSectionDialog(false);
   556→              }}
   557→              autoFocus
   558→            />
   559→          </div>
   560→          <DialogFooter>
   561→            <Button variant="outline" onClick={() => setShowSectionDialog(false)}>
   562→              Cancel
   563→            </Button>
   564→            <Button onClick={handleAddSection} disabled={!newSectionName.trim()}>
   565→              Create
   566→            </Button>
   567→          </DialogFooter>
   568→        </DialogContent>
   569→      </Dialog>
   570→    </div>
   571→  );
   572→};
   573→
   574→/**
   575→ * Empty state when no panels are added yet
   576→ */
   577→function EmptyDashboardState({ onAddPanel }: { onAddPanel: () => void }) {
   578→  return (
   579→    <div className="h-full flex flex-col items-center justify-center text-center p-8">
   580→      <div className="text-muted-foreground mb-4">
   581→        <svg className="h-16 w-16 mx-auto mb-4 opacity-30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
   582→          <rect x="3" y="3" width="7" height="7" rx="1" />
   583→          <rect x="14" y="3" width="7" height="7" rx="1" />
   584→          <rect x="3" y="14" width="7" height="7" rx="1" />
   585→          <rect x="14" y="14" width="7" height="7" rx="1" />
   586→        </svg>
   587→        <p className="text-sm">No panels yet. Add a panel to get started.</p>
   588→      </div>
   589→      <Button onClick={onAddPanel} className="gap-2">
   590→        <Plus className="h-4 w-4" />
   591→        Add Your First Panel
   592→      </Button>
   593→    </div>
   594→  );
   595→}
   596→
   597→/**
   598→ * Overlay buttons that appear in the dashboard header for editing panels
   599→ */
   600→function PanelEditOverlay({
   601→  panels,
   602→  onEditPanel,
   603→  onDeletePanel,
   604→}: {
   605→  panels: PanelDescriptor[];
   606→  onEditPanel: (index: number) => void;
   607→  onDeletePanel: (index: number) => void;
   608→}) {
   609→  if (panels.length === 0) return null;
   610→
   611→  return (
   612→    <DropdownMenu>
   613→      <DropdownMenuTrigger asChild>
   614→        <Button variant="outline" size="sm" className="h-7 text-xs gap-1">
   615→          <Edit2 className="h-3.5 w-3.5" />
   616→          Edit Panels
   617→        </Button>
   618→      </DropdownMenuTrigger>
   619→      <DropdownMenuContent align="end" className="w-64">
   620→        {panels.map((panel, index) => (
   621→          <DropdownMenuItem
   622→            key={index}
   623→            className="flex items-center justify-between"
   624→            onSelect={(e) => e.preventDefault()}
   625→          >
   626→            <span className="text-sm truncate mr-2">
   627→              {panel.titleOption?.title ?? `Panel ${index + 1}`}
   628→            </span>
   629→            <div className="flex items-center gap-1 shrink-0">
   630→              <Button
   631→                variant="ghost"
   632→                size="icon"
   633→                className="h-6 w-6"
   634→                onClick={() => onEditPanel(index)}
   635→              >
   636→                <Pencil className="h-3 w-3" />
   637→              </Button>
   638→              <Button
   639→                variant="ghost"
   640→                size="icon"
   641→                className="h-6 w-6 text-destructive hover:text-destructive"
   642→                onClick={() => onDeletePanel(index)}
   643→              >
   644→                <Trash2 className="h-3 w-3" />
   645→              </Button>
   646→            </div>
   647→          </DropdownMenuItem>
   648→        ))}
   649→      </DropdownMenuContent>
   650→    </DropdownMenu>
   651→  );
   652→}
   653→
   654→/**
   655→ * Flatten panels from dashboard config (handles groups)
   656→ */
   657→function flattenPanels(
   658→  panels: (PanelDescriptor | DashboardGroup)[]
   659→): PanelDescriptor[] {
   660→  const result: PanelDescriptor[] = [];
   661→  for (const item of panels) {
   662→    if ("charts" in item && Array.isArray((item as DashboardGroup).charts)) {
   663→      result.push(...(item as DashboardGroup).charts);
   664→    } else {
   665→      result.push(item as PanelDescriptor);
   666→    }
   667→  }
   668→  return result;
   669→}
   670→
   671→CustomDashboardTabComponent.displayName = "CustomDashboardTab";
   672→
   673→export const CustomDashboardTab = memo(CustomDashboardTabComponent);
   674→

