    14→} from "react";
    15→import type { Dashboard, DashboardGroup, PanelDescriptor } from "./dashboard-model";
    16→import type {
    17→  DashboardVisualizationComponent,
    18→  RefreshOptions,
    19→} from "./dashboard-visualization-layout";
    20→import { DashboardSection } from "./dashboard-section";
    21→import type { TimeSpan } from "./timespan-selector";
    22→
    23→export interface DashboardPanelContainerRef {
    24→  refresh: (timeSpan?: TimeSpan, filterExpression?: string) => void;
    25→}
    26→
    27→/**
    28→ * Interface for child components that can be refreshed by the dashboard.
    29→ * Children that implement this interface will be automatically refreshed
    30→ * when the dashboard is refreshed.
    31→ */
    32→export interface RefreshableChild {
    33→  refresh: (timeSpan?: TimeSpan, filterExpression?: string) => void;
    34→}
    35→
    36→/**
    37→ * Context for dashboard refresh registration.
    38→ * Child components can use the useDashboardRefresh hook to register
    39→ * themselves for automatic refresh when the dashboard refreshes.
    40→ */
    41→interface DashboardRefreshContextValue {
    42→  register: (child: RefreshableChild) => void;
    43→  unregister: (child: RefreshableChild) => void;
    44→}
    45→
    46→const DashboardRefreshContext = createContext<DashboardRefreshContextValue | null>(null);
    47→
    48→/**
    49→ * Hook for child components to register themselves for dashboard refresh.
    50→ * When the dashboard is refreshed, the provided refresh function will be called.
    51→ *
    52→ * @param refreshFn - Function to call when dashboard refreshes
    53→ *
    54→ * @example
    55→ * ```tsx
    56→ * const MyComponent = () => {
    57→ *   const fetchData = useCallback((timeSpan?: TimeSpan) => {
    58→ *     // fetch data...
    59→ *   }, []);
    60→ *
    61→ *   useDashboardRefresh(fetchData);
    62→ *
    63→ *   return <div>...</div>;
    64→ * };
    65→ * ```
    66→ */
    67→export function useDashboardRefresh(
    68→  refreshFn: (timeSpan?: TimeSpan, filterExpression?: string) => void
    69→) {
    70→  const ctx = useContext(DashboardRefreshContext);
    71→
    72→  useEffect(() => {
    73→    if (!ctx) return;
    74→
    75→    const child: RefreshableChild = { refresh: refreshFn };
    76→    ctx.register(child);
    77→
    78→    return () => {
    79→      ctx.unregister(child);
    80→    };
    81→  }, [ctx, refreshFn]);
    82→}
    83→
    84→interface DashboardPanelContainerProps {
    85→  dashboard: Dashboard;
    86→  /** Unique identifier for layout persistence */
    87→  dashboardId?: string;
    88→  initialTimeSpan?: TimeSpan;
    89→  initialFilterExpression?: string;
    90→  initialLoading?: boolean;
    91→  onChartSelection?: (
    92→    timeSpan: TimeSpan,
    93→    selection: { name: string; series: string; value: number }
    94→  ) => void;
    95→  /** Whether to show edit controls for sections (custom dashboards) */
    96→  showSectionEditControls?: boolean;
    97→  /** Callback when section is renamed */
    98→  onSectionRename?: (sectionIndex: number, newTitle: string) => void;
    99→  /** Callback when section is deleted */
   100→  onSectionDelete?: (sectionIndex: number) => void;
   101→  /** Callback when section collapse state changes */
   102→  onSectionCollapseChange?: (sectionIndex: number, collapsed: boolean) => void;
   103→  /**
   104→   * Children to render below the dashboard panels.
   105→   * Children can use the useDashboardRefresh hook to register
   106→   * themselves for automatic refresh when the dashboard refreshes.
   107→   */
   108→  children?: React.ReactNode;
   109→}
   110→
   111→// Helper function to check if an item is a DashboardGroup
   112→function isDashboardGroup(item: unknown): item is DashboardGroup {
   113→  return (
   114→    typeof item === "object" &&
   115→    item !== null &&
   116→    "title" in item &&
   117→    "charts" in item &&
   118→    Array.isArray((item as { charts: unknown }).charts)
   119→  );
   120→}
   121→
   122→// Helper function to flatten all charts (including charts in groups)
   123→function getAllCharts(charts: (PanelDescriptor | DashboardGroup)[]): PanelDescriptor[] {
   124→  const allCharts: PanelDescriptor[] = [];
   125→  charts.forEach((item) => {
   126→    if (isDashboardGroup(item)) {
   127→      allCharts.push(...item.charts);
   128→    } else {
   129→      allCharts.push(item);
   130→    }
   131→  });
   132→  return allCharts;
   133→}
   134→
   135→/** Single source of truth for dashboard grid column counts: mobile | tablet | desktop */
   136→export type DashboardGridColumns = 1 | 6 | 24;
   137→
   138→/** Represents a section with its panels and metadata */
   139→interface SectionInfo {
   140→  group: DashboardGroup | null; // null for ungrouped panels
   141→  sectionIndex: number;
   142→  panels: PanelDescriptor[];
   143→  globalPanelStartIndex: number; // Global index of first panel in this section
   144→}
   145→
   146→const DashboardPanelContainer = forwardRef<
   147→  DashboardPanelContainerRef,
   148→  DashboardPanelContainerProps
   149→>(
   150→  (
   151→    {
   152→      dashboard,
   153→      dashboardId,
   154→      initialTimeSpan,
   155→      initialFilterExpression,
   156→      initialLoading,
   157→      onChartSelection,
   158→      showSectionEditControls = false,
   159→      onSectionRename,
   160→      onSectionDelete,
   161→      onSectionCollapseChange,
   162→      children,
   163→    },
   164→    ref
   165→  ) => {
   166→    // Track section collapse states
   167→    const [sectionCollapseStates, setSectionCollapseStates] = useState<Map<number, boolean>>(new Map());
   168→    // Track individual panel collapse states (keyed by global panel index)
   169→    const [panelCollapseStates, setPanelCollapseStates] = useState<Map<number, boolean>>(new Map());
   170→    const subComponentRefs = useRef<(DashboardVisualizationComponent | null)[]>([]);
   171→
   172→    // Track registered refreshable children
   173→    const registeredChildrenRef = useRef<Set<RefreshableChild>>(new Set());
   174→
   175→    // Memoize the charts array from the dashboard
   176→    const panels = useMemo(() => dashboard.charts, [dashboard]);
   177→
   178→    // Build sections from dashboard panels
   179→    const sections = useMemo<SectionInfo[]>(() => {
   180→      const result: SectionInfo[] = [];
   181→      const ungroupedPanels: PanelDescriptor[] = [];
   182→      let globalPanelIndex = 0;
   183→      let sectionIndex = 0;
   184→
   185→      panels.forEach((item) => {
   186→        if (isDashboardGroup(item)) {
   187→          // This is a group - create a section for it
   188→          result.push({
   189→            group: item,
   190→            sectionIndex,
   191→            panels: item.charts,
   192→            globalPanelStartIndex: globalPanelIndex,
   193→          });
   194→          globalPanelIndex += item.charts.length;
   195→          sectionIndex++;
   196→        } else {
   197→          // Standalone panel - collect into ungrouped
   198→          ungroupedPanels.push(item);
   199→        }
   200→      });
   201→
   202→      // If there are ungrouped panels, add them as the last section (without header)
   203→      if (ungroupedPanels.length > 0) {
   204→        // Find the correct global start index for ungrouped panels
   205→        // They may be interleaved with groups, so we need to recalculate
   206→        let ungroupedStartIndex = 0;
   207→        panels.forEach((item) => {
   208→          if (isDashboardGroup(item)) {
   209→            ungroupedStartIndex += item.charts.length;
   210→          }
   211→        });
   212→
   213→        result.push({
   214→          group: null, // null indicates ungrouped section
   215→          sectionIndex,
   216→          panels: ungroupedPanels,
   217→          globalPanelStartIndex: ungroupedStartIndex,
   218→        });
   219→      }
   220→
   221→      return result;
   222→    }, [panels]);
   223→
   224→    // Initialize section collapse states from dashboard groups
   225→    useEffect(() => {
   226→      sections.forEach((section) => {
   227→        if (section.group && !sectionCollapseStates.has(section.sectionIndex)) {
   228→          setSectionCollapseStates((prev) => {
   229→            const next = new Map(prev);
   230→            next.set(section.sectionIndex, section.group?.collapsed ?? false);
   231→            return next;
   232→          });
   233→        }
   234→      });
   235→    }, [sections, sectionCollapseStates]);
   236→
   237→    // Initialize panel collapse states from descriptors
   238→    useEffect(() => {
   239→      sections.forEach((section) => {
   240→        section.panels.forEach((panel, localIndex) => {
   241→          const globalIndex = section.globalPanelStartIndex + localIndex;
   242→          if (!panelCollapseStates.has(globalIndex)) {
   243→            setPanelCollapseStates((prev) => {
   244→              const next = new Map(prev);
   245→              next.set(globalIndex, panel.collapsed ?? false);
   246→              return next;
   247→            });
   248→          }
   249→        });
   250→      });
   251→    }, [sections, panelCollapseStates]);
   252→
   253→    const toggleSection = useCallback((sectionIndex: number) => {
   254→      setSectionCollapseStates((prev) => {
   255→        const next = new Map(prev);
   256→        const newCollapsed = !(next.get(sectionIndex) ?? false);
   257→        next.set(sectionIndex, newCollapsed);
   258→        // Notify parent of collapse state change for persistence
   259→        onSectionCollapseChange?.(sectionIndex, newCollapsed);
   260→        return next;
   261→      });
   262→    }, [onSectionCollapseChange]);
   263→
   264→    const onPanelCollapsedChange = useCallback((globalPanelIndex: number, isCollapsed: boolean) => {
   265→      setPanelCollapseStates((prev) => {
   266→        const next = new Map(prev);
   267→        next.set(globalPanelIndex, isCollapsed);
   268→        return next;
   269→      });
   270→    }, []);
   271→
   272→    // Function to connect all chart instances together
   273→    const connectAllCharts = useCallback(() => {
   274→      const chartInstances: echarts.ECharts[] = subComponentRefs.current
   275→        .filter(
   276→          (chartRef): chartRef is DashboardVisualizationComponent =>
   277→            chartRef !== null &&
   278→            typeof (chartRef as unknown as { getEChartInstance?: () => echarts.ECharts })
   279→              .getEChartInstance === "function"
   280→        )
   281→        .map((chartRef) => {
   282→          const component = chartRef as unknown as { getEChartInstance: () => echarts.ECharts };
   283→          return component.getEChartInstance();
   284→        })
   285→        .filter((echartInstance) => echartInstance !== undefined);
   286→
   287→      if (chartInstances.length === 0) {
   288→        return;
   289→      }
   290→
   291→      const allCharts = getAllCharts(panels);
   292→      const chartNumber = allCharts.filter(
   293→        (chart: PanelDescriptor) => chart.type !== "table"
   294→      ).length;
   295→      if (chartInstances.length === chartNumber) {
   296→        // Connect all echarts together on this page
   297→        connect(chartInstances);
   298→      }
   299→    }, [panels]);
   300→
   301→    // Callback when a subcomponent is mounted or unmounted
   302→    const onSubComponentUpdated = useCallback(
   303→      (subComponent: DashboardVisualizationComponent | null, globalIndex: number) => {
   304→        subComponentRefs.current[globalIndex] = subComponent;
   305→        connectAllCharts();
   306→      },
   307→      [connectAllCharts]
   308→    );
   309→
   310→    const refreshAllCharts = useCallback(
   311→      (newTimeSpan?: TimeSpan, newFilterExpression?: string) => {
   312→        const refreshParam: RefreshOptions = {
   313→          timeSpan: newTimeSpan ?? initialTimeSpan,
